struct Promo: Equatable {
    let code: String
    let discount: Int
}

final class UserAccount: ObservableObject {
    let id: String
    @Published var appliedPromoCode: String?
    @Published var appliedDiscountPercent: Int?

    init(id: String) {
        self.id = id
    }
}

@MainActor
final class PromoManager: ObservableObject {
    static let shared = PromoManager()

    @Published private(set) var lastAppliedPromo: Promo?
    @Published private(set) var currentUser: UserAccount

    private init() {
        self.currentUser = UserAccount(id: Self.loadOrCreateUserID())
        self.currentUser.appliedPromoCode = UserDefaults.standard.string(forKey: Keys.appliedPromoCode)
        if UserDefaults.standard.object(forKey: Keys.appliedDiscountPercent) != nil {
            self.currentUser.appliedDiscountPercent = UserDefaults.standard.integer(forKey: Keys.appliedDiscountPercent)
        }
        if let code = currentUser.appliedPromoCode, let discount = currentUser.appliedDiscountPercent {
            self.lastAppliedPromo = Promo(code: code, discount: discount)
        }
    }

    func handleIncomingURL(_ url: URL) {
        guard let promo = Self.parsePromoURL(url) else { return }
        applyPromoToCurrentUser(promo)
    }

    func applyPromoToCurrentUser(_ promo: Promo) {
        currentUser.appliedPromoCode = promo.code
        currentUser.appliedDiscountPercent = promo.discount
        lastAppliedPromo = promo

        UserDefaults.standard.set(promo.code, forKey: Keys.appliedPromoCode)
        UserDefaults.standard.set(promo.discount, forKey: Keys.appliedDiscountPercent)
        UserDefaults.standard.set(Date().timeIntervalSince1970, forKey: Keys.lastAppliedTimestamp)
    }

    static func parsePromoURL(_ url: URL) -> Promo? {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: false) else { return nil }

        let host = components.host?.lowercased()
        guard host == "myapp.com" else { return nil }

        let path = components.path.lowercased()
        guard path == "/promo" else { return nil }

        let items = components.queryItems ?? []
        let code = items.first(where: { $0.name.lowercased() == "code" })?.value?.trimmingCharacters(in: .whitespacesAndNewlines)
        let discountStr = items.first(where: { $0.name.lowercased() == "discount" })?.value?.trimmingCharacters(in: .whitespacesAndNewlines)

        guard let codeUnwrapped = code, !codeUnwrapped.isEmpty,
              let discountRaw = discountStr, let discount = Int(discountRaw),
              (0...100).contains(discount) else { return nil }

        return Promo(code: codeUnwrapped, discount: discount)
    }

    private static func loadOrCreateUserID() -> String {
        if let existing = UserDefaults.standard.string(forKey: Keys.userID) { return existing }
        let newID = UUID().uuidString
        UserDefaults.standard.set(newID, forKey: Keys.userID)
        return newID
    }

    private enum Keys {
        static let userID = "user.id"
        static let appliedPromoCode = "user.promo.code"
        static let appliedDiscountPercent = "user.promo.discountPercent"
        static let lastAppliedTimestamp = "user.promo.lastAppliedTimestamp"
    }
}